mapper.select:
SELECT scdt.*
FROM school_calendar_date_type scdt
         LEFT JOIN school_calendar sc ON sc.id = scdt.school_calendar_id
WHERE scdt.deleted = 0
  AND sc.deleted = 0

    AND sc.school_id = #{schoolId}


    AND scdt.type = #{type}


    AND scdt.apply_type = #{applyType}


    AND scdt.calendar_date >= #{startDate}


    AND scdt.calendar_date <= #{endDate}
